<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Kanban Board</title>
<style>
  * { box-sizing: border-box; }
  body {
    margin: 0;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
    background: #f0f2f5;
    color: #1a1a2e;
    min-height: 100vh;
  }
  header.app-header {
    padding: 24px 32px 8px;
  }
  header.app-header h1 {
    margin: 0 0 16px;
    font-size: 24px;
    font-weight: 700;
    letter-spacing: -0.02em;
  }
  .add-bar {
    display: flex;
    gap: 8px;
    max-width: 480px;
  }
  #new-card {
    flex: 1;
    padding: 10px 14px;
    border: 1px solid #d0d3d9;
    border-radius: 8px;
    font-size: 14px;
    outline: none;
    transition: border-color 0.15s, box-shadow 0.15s;
  }
  #new-card:focus {
    border-color: #4f6bed;
    box-shadow: 0 0 0 3px rgba(79,107,237,0.15);
  }
  #add-card {
    padding: 10px 18px;
    border: none;
    border-radius: 8px;
    background: #4f6bed;
    color: #fff;
    font-size: 14px;
    font-weight: 600;
    cursor: pointer;
    transition: background 0.15s;
  }
  #add-card:hover { background: #3d55d1; }
  #add-card:active { background: #3348b8; }

  .board {
    display: flex;
    gap: 20px;
    padding: 24px 32px 40px;
    align-items: flex-start;
    overflow-x: auto;
  }
  .column {
    flex: 1;
    min-width: 260px;
    background: #e9ebf0;
    border-radius: 12px;
    padding: 12px;
    display: flex;
    flex-direction: column;
    transition: background 0.15s, box-shadow 0.15s;
  }
  .column.drag-over {
    background: #dde2f5;
    box-shadow: inset 0 0 0 2px #4f6bed;
  }
  .col-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 4px 8px 12px;
  }
  .col-title {
    font-size: 13px;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    color: #5a5f6e;
  }
  .count {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    min-width: 22px;
    height: 22px;
    padding: 0 7px;
    border-radius: 11px;
    background: #cfd3dd;
    color: #4a4f5e;
    font-size: 12px;
    font-weight: 700;
  }
  .cards {
    display: flex;
    flex-direction: column;
    gap: 10px;
    min-height: 60px;
    flex: 1;
  }
  .card {
    background: #fff;
    border-radius: 10px;
    padding: 12px 14px;
    box-shadow: 0 1px 2px rgba(16,24,40,0.06), 0 1px 3px rgba(16,24,40,0.1);
    cursor: grab;
    display: flex;
    align-items: flex-start;
    justify-content: space-between;
    gap: 10px;
    font-size: 14px;
    line-height: 1.4;
    transition: box-shadow 0.15s, transform 0.05s;
  }
  .card:hover {
    box-shadow: 0 2px 4px rgba(16,24,40,0.1), 0 4px 8px rgba(16,24,40,0.12);
  }
  .card:active { cursor: grabbing; }
  .card.dragging {
    opacity: 0.5;
    transform: rotate(1.5deg);
  }
  .card-title {
    flex: 1;
    word-break: break-word;
    white-space: pre-wrap;
  }
  .card-del {
    flex-shrink: 0;
    width: 22px;
    height: 22px;
    border: none;
    border-radius: 6px;
    background: transparent;
    color: #9aa0ac;
    font-size: 16px;
    line-height: 1;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: background 0.15s, color 0.15s;
  }
  .card-del:hover {
    background: #fdecec;
    color: #e5484d;
  }
</style>
</head>
<body>
  <header class="app-header">
    <h1>Kanban Board</h1>
    <div class="add-bar">
      <input id="new-card" type="text" placeholder="What needs doing?" autocomplete="off">
      <button id="add-card">Add card</button>
    </div>
  </header>

  <main class="board">
    <section class="column" id="col-todo" data-col="todo">
      <div class="col-header">
        <span class="col-title">To Do</span>
        <span class="count">0</span>
      </div>
      <div class="cards"></div>
    </section>
    <section class="column" id="col-doing" data-col="doing">
      <div class="col-header">
        <span class="col-title">Doing</span>
        <span class="count">0</span>
      </div>
      <div class="cards"></div>
    </section>
    <section class="column" id="col-done" data-col="done">
      <div class="col-header">
        <span class="col-title">Done</span>
        <span class="count">0</span>
      </div>
      <div class="cards"></div>
    </section>
  </main>

<script>
(function () {
  "use strict";

  const STORAGE_KEY = "kanban.board.v1";
  const COLUMNS = ["todo", "doing", "done"];

  // state: array of { id, title, col }
  let cards = [];
  let nextId = 1;

  function load() {
    try {
      const raw = localStorage.getItem(STORAGE_KEY);
      if (raw) {
        const data = JSON.parse(raw);
        if (Array.isArray(data.cards)) {
          cards = data.cards.filter(c =>
            c && typeof c.id === "number" &&
            typeof c.title === "string" &&
            COLUMNS.includes(c.col));
        }
        if (typeof data.nextId === "number") nextId = data.nextId;
      }
    } catch (e) {
      cards = [];
    }
    // ensure nextId is safe
    cards.forEach(c => { if (c.id >= nextId) nextId = c.id + 1; });
  }

  function save() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify({ cards, nextId }));
  }

  function cardsContainer(col) {
    return document.querySelector("#col-" + col + " .cards");
  }

  function buildCardEl(card) {
    const el = document.createElement("div");
    el.className = "card";
    el.setAttribute("draggable", "true");
    el.dataset.id = String(card.id);

    const title = document.createElement("span");
    title.className = "card-title";
    title.textContent = card.title;

    const del = document.createElement("button");
    del.className = "card-del";
    del.type = "button";
    del.setAttribute("aria-label", "Delete card");
    del.textContent = "\u00D7";
    del.addEventListener("click", function (e) {
      e.stopPropagation();
      deleteCard(card.id);
    });

    el.appendChild(title);
    el.appendChild(del);

    el.addEventListener("dragstart", function (e) {
      el.classList.add("dragging");
      e.dataTransfer.effectAllowed = "move";
      e.dataTransfer.setData("text/plain", String(card.id));
    });
    el.addEventListener("dragend", function () {
      el.classList.remove("dragging");
    });

    return el;
  }

  function render() {
    COLUMNS.forEach(col => {
      cardsContainer(col).innerHTML = "";
    });
    cards.forEach(card => {
      cardsContainer(card.col).appendChild(buildCardEl(card));
    });
    updateCounts();
  }

  function updateCounts() {
    COLUMNS.forEach(col => {
      const count = cards.filter(c => c.col === col).length;
      document.querySelector("#col-" + col + " .count").textContent = String(count);
    });
  }

  function addCard(title) {
    const trimmed = title.trim();
    if (!trimmed) return;
    const card = { id: nextId++, title: trimmed, col: "todo" };
    cards.push(card);
    cardsContainer("todo").appendChild(buildCardEl(card));
    updateCounts();
    save();
  }

  function deleteCard(id) {
    const idx = cards.findIndex(c => c.id === id);
    if (idx === -1) return;
    cards.splice(idx, 1);
    const el = document.querySelector('.card[data-id="' + id + '"]');
    if (el) el.remove();
    updateCounts();
    save();
  }

  function moveCard(id, col) {
    const card = cards.find(c => c.id === id);
    if (!card || !COLUMNS.includes(col)) return;
    if (card.col !== col) {
      card.col = col;
      save();
    }
    // move DOM node (re-append even if same column is harmless)
    const el = document.querySelector('.card[data-id="' + id + '"]');
    if (el) cardsContainer(col).appendChild(el);
    updateCounts();
  }

  // Wire up columns for drag-and-drop
  COLUMNS.forEach(col => {
    const column = document.getElementById("col-" + col);

    column.addEventListener("dragover", function (e) {
      e.preventDefault();
      e.dataTransfer.dropEffect = "move";
      column.classList.add("drag-over");
    });
    column.addEventListener("dragleave", function (e) {
      // only clear when leaving the column entirely
      if (!column.contains(e.relatedTarget)) {
        column.classList.remove("drag-over");
      }
    });
    column.addEventListener("drop", function (e) {
      e.preventDefault();
      column.classList.remove("drag-over");
      const id = parseInt(e.dataTransfer.getData("text/plain"), 10);
      if (!isNaN(id)) moveCard(id, col);
    });
  });

  // Add-card controls
  const input = document.getElementById("new-card");
  const addBtn = document.getElementById("add-card");

  addBtn.addEventListener("click", function () {
    addCard(input.value);
    input.value = "";
    input.focus();
  });
  input.addEventListener("keydown", function (e) {
    if (e.key === "Enter") {
      addCard(input.value);
      input.value = "";
    }
  });

  // Init
  load();
  render();
})();
</script>
</body>
</html>
